import pytest

from calculator import add, divide


class TestAdd:
    """Tests for calculator.add."""

    def test_add_two_positive_numbers(self) -> None:
        assert add(2.0, 3.0) == 5.0

    def test_add_positive_and_negative(self) -> None:
        assert add(5.0, -2.0) == 3.0

    def test_add_two_negative_numbers(self) -> None:
        assert add(-1.5, -2.5) == -4.0

    def test_add_zero_identity(self) -> None:
        assert add(7.0, 0.0) == 7.0
        assert add(0.0, 7.0) == 7.0

    def test_add_floats(self) -> None:
        assert add(0.1, 0.2) == pytest.approx(0.3)


class TestDivide:
    """Tests for calculator.divide."""

    def test_divide_even_result(self) -> None:
        assert divide(10.0, 2.0) == 5.0

    def test_divide_fractional_result(self) -> None:
        assert divide(1.0, 4.0) == 0.25

    def test_divide_negative_numerator(self) -> None:
        assert divide(-6.0, 3.0) == -2.0

    def test_divide_negative_denominator(self) -> None:
        assert divide(6.0, -3.0) == -2.0

    def test_divide_two_negatives(self) -> None:
        assert divide(-6.0, -3.0) == 2.0

    def test_divide_by_one_returns_numerator(self) -> None:
        assert divide(42.0, 1.0) == 42.0

    def test_divide_zero_numerator(self) -> None:
        assert divide(0.0, 5.0) == 0.0

    def test_divide_by_zero_raises_zero_division_error(self) -> None:
        with pytest.raises(ZeroDivisionError):
            divide(1.0, 0.0)

    def test_divide_zero_by_zero_raises_zero_division_error(self) -> None:
        with pytest.raises(ZeroDivisionError):
            divide(0.0, 0.0)
